// HGEMM naive: compute one c[i,j]
// element per threads, all row major
__global__ void hgemm_naive_f16_kernel(half *a, half *b, half *c, int M, int N,
                                       int K) {
  int n = blockIdx.x * blockDim.x + threadIdx.x;
